mapper.select:
SELECT GROUP_ID as groupId, GROUP_NM as groupNm, GROUP_DC as groupDc, GROUP_CREAT_DE as groupCreatDe
  FROM LETTNAUTHORGROUPINFO 
 WHERE GROUP_ID=#{groupId}

mapper.insert:
 INSERT INTO LETTNAUTHORGROUPINFO 
       ( GROUP_ID
       , GROUP_NM
       , GROUP_DC
       , GROUP_CREAT_DE )
VALUES ( #{groupId}
       , #{groupNm}
       , #{groupDc}
       , now())

mapper.update:
UPDATE LETTNAUTHORGROUPINFO 
   SET GROUP_NM=#{groupNm}
     , GROUP_DC=#{groupDc}
     , GROUP_CREAT_DE=now()
 WHERE GROUP_ID=#{groupId}
